# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3
import logging
from datetime import datetime
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

NOTIFICATION_TYPES = {
    'alert': {
        'subject_prefix': '[ALERT]',
        'default_priority': 'high',
        'requires_immediate': True
    },
    'info': {
        'subject_prefix': '[INFO]',
        'default_priority': 'low',
        'requires_immediate': False
    },
    'warning': {
        'subject_prefix': '[WARNING]',
        'default_priority': 'medium',
        'requires_immediate': False
    },
    'critical': {
        'subject_prefix': '[CRITICAL]',
        'default_priority': 'critical',
        'requires_immediate': True
    },
    'transactional': {
        'subject_prefix': '[TRANSACTION]',
        'default_priority': 'medium',
        'requires_immediate': True
    }
}


def validate_event(event):
    """Validate required fields in the event payload."""
    required_fields = ['topic_arn', 'message', 'notification_type']
    missing_fields = [field for field in required_fields if field not in event]

    if missing_fields:
        raise ValueError(f"Missing required fields: {', '.join(missing_fields)}")

    notification_type = event['notification_type']
    if notification_type not in NOTIFICATION_TYPES:
        raise ValueError(
            f"Invalid notification_type '{notification_type}'. "
            f"Must be one of: {', '.join(NOTIFICATION_TYPES.keys())}"
        )

    if not event['topic_arn'].startswith('arn:aws:sns:'):
        raise ValueError(f"Invalid topic ARN format: {event['topic_arn']}")

    return True


def build_message(event):
    """Build the SNS message payload based on notification type."""
    notification_type = event['notification_type']
    config = NOTIFICATION_TYPES[notification_type]

    message_body = event['message']
    subject = event.get('subject', 'Notification')
    subject = f"{config['subject_prefix']} {subject}"

    # SNS subject max length is 100 characters
    if len(subject) > 100:
        subject = subject[:97] + '...'

    priority = event.get('priority', config['default_priority'])

    metadata = {
        'notification_type': notification_type,
        'priority': priority,
        'timestamp': datetime.utcnow().isoformat(),
        'source': event.get('source', 'event-notification-system'),
        'correlation_id': event.get('correlation_id', ''),
        'requires_immediate': config['requires_immediate']
    }

    # Build structured message for different protocols
    structured_message = {
        'default': json.dumps({
            'message': message_body,
            'metadata': metadata
        }),
        'email': build_email_message(message_body, metadata, subject),
        'sms': build_sms_message(message_body, notification_type),
        'lambda': json.dumps({
            'message': message_body,
            'metadata': metadata,
            'raw_event': event
        })
    }

    return {
        'subject': subject,
        'message': json.dumps(structured_message),
        'message_structure': 'json',
        'message_attributes': build_message_attributes(notification_type, priority, event),
        'metadata': metadata
    }


def build_email_message(message_body, metadata, subject):
    """Build email-formatted message."""
    email_message = f"""
{subject}
{'=' * len(subject)}

{message_body}

---
Notification Details:
- Type: {metadata['notification_type']}
- Priority: {metadata['priority']}
- Timestamp: {metadata['timestamp']}
- Source: {metadata['source']}
- Correlation ID: {metadata.get('correlation_id', 'N/A')}

This is an automated notification from the Event Notification System.
    """
    return email_message.strip()


def build_sms_message(message_body, notification_type):
    """Build SMS-formatted message (concise)."""
    prefix = NOTIFICATION_TYPES[notification_type]['subject_prefix']
    max_sms_length = 160
    available_length = max_sms_length - len(prefix) - 1
    truncated_message = message_body[:available_length]
    if len(message_body) > available_length:
        truncated_message = truncated_message[:-3] + '...'
    return f"{prefix} {truncated_message}"


def build_message_attributes(notification_type, priority, event):
    """Build SNS message attributes for filtering."""
    attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type
        },
        'priority': {
            'DataType': 'String',
            'StringValue': priority
        },
        'source': {
            'DataType': 'String',
            'StringValue': event.get('source', 'event-notification-system')
        }
    }

    if event.get('correlation_id'):
        attributes['correlation_id'] = {
            'DataType': 'String',
            'StringValue': event['correlation_id']
        }

    # Add custom attributes if provided
    custom_attributes = event.get('custom_attributes', {})
    for key, value in custom_attributes.items():
        if isinstance(value, str):
            attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }

    return attributes


def publish_to_sns(topic_arn, message_data):
    """Publish message to SNS topic."""
    try:
        publish_params = {
            'TopicArn': topic_arn,
            'Message': message_data['message'],
            'Subject': message_data['subject'],
            'MessageStructure': message_data['message_structure'],
            'MessageAttributes': message_data['message_attributes']
        }

        response = sns_client.publish(**publish_params)

        logger.info(f"Message published successfully. MessageId: {response['MessageId']}")

        return {
            'message_id': response['MessageId'],
            'status': 'success',
            'topic_arn': topic_arn,
            'metadata': message_data['metadata']
        }

    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        logger.error(f"Failed to publish to SNS. Error: {error_code} - {error_message}")
        raise


def publish_batch(events):
    """Handle batch publishing of multiple notifications."""
    results = []
    errors = []

    for idx, event in enumerate(events):
        try:
            validate_event(event)
            message_data = build_message(event)
            result = publish_to_sns(event['topic_arn'], message_data)
            results.append({
                'index': idx,
                **result
            })
        except Exception as e:
            logger.error(f"Error processing batch item {idx}: {str(e)}")
            errors.append({
                'index': idx,
                'error': str(e),
                'status': 'failed'
            })

    return {
        'successful': results,
        'failed': errors,
        'total_processed': len(events),
        'success_count': len(results),
        'failure_count': len(errors)
    }


def lambda_handler(event, context):
    """
    Main Lambda handler for the Event Notification System.

    Expected event formats:

    Single notification:
    {
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "message": "Server CPU usage exceeded 90%",
        "notification_type": "alert",  // alert, info, warning, critical, transactional
        "subject": "High CPU Usage Alert",  // optional
        "priority": "high",  // optional, defaults based on notification_type
        "source": "monitoring-service",  // optional
        "correlation_id": "abc-123-def",  // optional
        "custom_attributes": {  // optional
            "environment": "production",
            "service": "web-api"
        }
    }

    Batch notifications:
    {
        "batch": true,
        "notifications": [
            { ... notification 1 ... },
            { ... notification 2 ... }
        ]
    }
    """
    logger.info(f"Received event: {json.dumps(event)}")

    try:
        # Check if this is a batch request
        if event.get('batch', False) and 'notifications' in event:
            notifications = event['notifications']

            if not isinstance(notifications, list) or len(notifications) == 0:
                return {
                    'statusCode': 400,
                    'body': json.dumps({
                        'error': 'Batch notifications must be a non-empty list'
                    })
                }

            logger.info(f"Processing batch of {len(notifications)} notifications")
            batch_results = publish_batch(notifications)

            status_code = 200 if batch_results['failure_count'] == 0 else 207

            return {
                'statusCode': status_code,
                'body': json.dumps(batch_results, default=str)
            }

        # Single notification processing
        validate_event(event)

        message_data = build_message(event)
        logger.info(
            f"Publishing {event['notification_type']} notification "
            f"to topic: {event['topic_arn']}"
        )

        result = publish_to_sns(event['topic_arn'], message_data)

        return {
            'statusCode': 200,
            'body': json.dumps(result, default=str)
        }

    except ValueError as e:
        logger.error(f"Validation error: {str(e)}")
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'Validation error',
                'message': str(e),
                'status': 'failed'
            })
        }

    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']

        if error_code == 'NotFound':
            status_code = 404
        elif error_code == 'AuthorizationError':
            status_code = 403
        elif error_code == 'Throttling':
            status_code = 429
        else:
            status_code = 500

        return {
            'statusCode': status_code,
            'body': json.dumps({
                'error': error_code,
                'message': error_message,
                'status': 'failed'
            })
        }

    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}", exc_info=True)
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal server error',
                'message': str(e),
                'status': 'failed'
            })
        }